def predict_next_frame(frame, action, xy=None):
    """
    Deterministic predictor for the 64×64 grid game.
    Each ACTION toggles a predefined set of cells between two colour values.
    - ACTION1 : fixed list (no coordinate dependence).
    - ACTION2 : three rectangular clusters; the cluster that is affected
                depends on the click coordinate `xy` (column, row).
                If xy lies in none of them nothing changes.
    - ACTION3 : four zones (independent of xy):
        * rows 48,49,59,60 & cols 22‑26   : swap 3 ↔ 0
        * rows 48,49,59,60 & cols 29‑33   : swap 0 ↔ 3
        * rows 48,49,59,60 & cols 36‑40   : swap 3 ↔ 0
        * rows 48,49,59,60 & cols 43‑47   : swap 0 ↔ 3
    - ACTION4 : the inverse of ACTION3 on exactly the same cells.
    All other actions are treated as no‑ops.
    """
    # copy frame
    new_frame = [row[:] for row in frame]

    def toggle(r, c, a, b):
        cur = new_frame[r][c]
        if cur == a:
            new_frame[r][c] = b
        elif cur == b:
            new_frame[r][c] = a

    # ---------- ACTION implementations ----------
    if action == "ACTION1":
        for r, c, a, b in [
            (52, 26, 7, 5), (53, 22, 7, 5), (53, 25, 5, 7),
            (53, 26, 7, 5), (54, 23, 5, 7), (54, 24, 5, 7),
            (54, 25, 5, 7), (55, 22, 7, 5), (55, 23, 5, 7),
            (55, 26, 7, 5), (56, 22, 7, 5), (63, 3, 1, 4)
        ]:
            toggle(r, c, a, b)

    elif action == "ACTION2":
        # three possible clusters
        if xy is None:
            return new_frame
        x, y = xy
        clusters = [
            # left cluster
            ((29, 33), (52, 56), [
                (52, 29, 7, 5), (52, 31, 5, 7),
                (53, 33, 5, 7), (54, 31, 5, 7), (54, 32, 7, 5),
                (54, 33, 5, 7), (55, 30, 5, 7), (55, 31, 5, 7),
                (55, 33, 5, 7), (56, 29, 7, 5), (56, 30, 7, 5),
                (56, 32, 7, 5), (56, 33, 7, 5), (63, 53, 1, 4)
            ]),
            # middle cluster
            ((36, 40), (52, 56), [
                (52, 36, 7, 5), (52, 37, 7, 5),
                (53, 36, 7, 5), (53, 38, 5, 7),
                (55, 36, 5, 7), (55, 37, 7, 5),
                (55, 38, 5, 7), (55, 39, 7, 5),
                (56, 36, 5, 7), (56, 39, 7, 5)
            ]),
            # right cluster
            ((43, 46), (52, 56), [
                (52, 43, 7, 5), (52, 44, 7, 5),
                (53, 43, 7, 5), (53, 45, 5, 7),
                (55, 43, 5, 7), (55, 44, 7, 5),
                (55, 45, 5, 7), (55, 46, 7, 5),
                (56, 43, 5, 7), (56, 46, 7, 5)
            ])
        ]
        for col_range, row_range, cells in clusters:
            if col_range[0] <= x <= col_range[1] and row_range[0] <= y <= row_range[1]:
                for r, c, a, b in cells:
                    toggle(r, c, a, b)
                break

    elif action == "ACTION3":
        rows = (48, 49, 59, 60)
        # 22‑26 : 3↔0
        for r in rows:
            for c in range(22, 27):
                toggle(r, c, 3, 0)
        # 29‑33 : 0↔3
        for r in rows:
            for c in range(29, 34):
                toggle(r, c, 0, 3)
        # 36‑40 : 3↔0
        for r in rows:
            for c in range(36, 41):
                toggle(r, c, 3, 0)
        # 43‑47 : 0↔3
        for r in rows:
            for c in range(43, 48):
                toggle(r, c, 0, 3)

    elif action == "ACTION4":
        rows = (48, 49, 59, 60)
        # inverse of ACTION3
        for r in rows:
            for c in range(22, 27):
                toggle(r, c, 0, 3)
        for r in rows:
            for c in range(29, 34):
                toggle(r, c, 3, 0)
        for r in rows:
            for c in range(36, 41):
                toggle(r, c, 0, 3)
        for r in rows:
            for c in range(43, 48):
                toggle(r, c, 3, 0)

    # other actions: no change
    return new_frame
